import Foundation

public enum OfficeTemplateData {
    public static func data(forFileExtension fileExtension: String) -> Data? {
        let normalizedExtension = fileExtension.trimmingCharacters(in: CharacterSet(charactersIn: ".")).lowercased()

        switch normalizedExtension {
        case "docx":
            return Data(base64Encoded: docxBase64)
        case "xlsx":
            return Data(base64Encoded: xlsxBase64)
        case "pptx":
            return Data(base64Encoded: pptxBase64)
        default:
            return nil
        }
    }

    private static let docxBase64 = ""
    private static let xlsxBase64 = ""
    private static let pptxBase64 = ""
}
